use fastly::backend::{Backend, BackendCreationError, BackendExt, SslVersion};
use fastly::{Error, Request, Response};
use std::time::Duration;

fn build_backend(
    name: &str,
    host: &str,
    port: u16,
    sni_hostname: Option<&str>,
    use_ssl: bool,
    min_tls: Option<SslVersion>,
    max_tls: Option<SslVersion>,
) -> Result<Backend, BackendCreationError> {
    let mut builder = Backend::builder(name, format!("{host}:{port}"));

    builder = builder
        .override_host(host)
        .connect_timeout(Duration::from_secs(3))
        .first_byte_timeout(Duration::from_secs(15))
        .between_bytes_timeout(Duration::from_secs(10));

    if use_ssl {
        builder = builder.enable_ssl();

        if let Some(sni) = sni_hostname {
            builder = builder.sni_hostname(sni);
        }

        if let Some(min) = min_tls {
            builder = builder.min_tls_version(min);
        }

        if let Some(max) = max_tls {
            builder = builder.max_tls_version(max);
        }
    }

    builder.finish()
}

fn select_backend(req: &Request) -> &'static str {
    let path = req.get_path();

    if path.starts_with("/api/") {
        "api_backend"
    } else if path.starts_with("/static/") {
        "static_backend"
    } else {
        "default_backend"
    }
}

